69	// CSRFTokenStore validates a CSRF token presented on a write request. The
70	// production implementation stores a per-process token issued at server
71	// startup and rotated via an explicit endpoint; tests inject a stub.
72	type CSRFTokenStore interface {
73		Validate(token string) bool
74	}
75	
76	// IdempotencyCache deduplicates operatorPromptSubmit calls by key within
77	// OperatorPromptIdempotencyTTL. Lookup returns the original bead ID stored
78	// under key (and true) when the key was previously seen and has not expired,
79	// or "", false otherwise. Store records key -> beadID at submit time.
80	type IdempotencyCache interface {
81		Lookup(key string) (string, bool)
82		Store(key, beadID string)
83	}
84	
85	// MemoryIdempotencyCache is a process-local in-memory IdempotencyCache with
86	// TTL-based eviction. It is safe for concurrent use.
87	type MemoryIdempotencyCache struct {
88		mu  sync.Mutex
89		now func() time.Time
90		ttl time.Duration
91		m   map[string]idempotencyEntry
92	}
93	
94	type idempotencyEntry struct {
95		beadID    string
96		expiresAt time.Time
97	}
98	
99	// NewMemoryIdempotencyCache constructs a cache with the operator-prompt
100	// default 24h TTL and the real wall clock.
101	func NewMemoryIdempotencyCache() *MemoryIdempotencyCache {
102		return &MemoryIdempotencyCache{
103			now: time.Now,
104			ttl: OperatorPromptIdempotencyTTL,
105			m:   make(map[string]idempotencyEntry),
106		}
107	}
108	
109	// Lookup returns the bead ID associated with key when present and unexpired.
110	func (c *MemoryIdempotencyCache) Lookup(key string) (string, bool) {
111		if key == "" {
112			return "", false
113		}
114		c.mu.Lock()
115		defer c.mu.Unlock()
116		e, ok := c.m[key]
117		if !ok {
118			return "", false
119		}
120		if c.now().After(e.expiresAt) {
121			delete(c.m, key)
122			return "", false
123		}
124		return e.beadID, true
125	}
126	
127	// Store records key -> beadID with the configured TTL window.
128	func (c *MemoryIdempotencyCache) Store(key, beadID string) {
129		if key == "" {
130			return
131		}
132		c.mu.Lock()
133		defer c.mu.Unlock()
134		c.m[key] = idempotencyEntry{beadID: beadID, expiresAt: c.now().Add(c.ttl)}
135	}
