137	// StaticCSRFTokenStore is a single-secret CSRFTokenStore — the token is
138	// generated once at server startup and validated by constant-time compare.
139	type StaticCSRFTokenStore struct {
140		token string
141	}
142	
143	// NewStaticCSRFTokenStore returns a store seeded with a freshly-generated
144	// 32-byte random token.
145	func NewStaticCSRFTokenStore() (*StaticCSRFTokenStore, error) {
146		var buf [32]byte
147		if _, err := rand.Read(buf[:]); err != nil {
148			return nil, fmt.Errorf("csrf: generate token: %w", err)
149		}
150		return &StaticCSRFTokenStore{token: hex.EncodeToString(buf[:])}, nil
151	}
152	
153	// NewStaticCSRFTokenStoreWithToken constructs a store using the supplied
154	// token (used by tests so a deterministic header value can be sent).
155	func NewStaticCSRFTokenStoreWithToken(token string) *StaticCSRFTokenStore {
156		return &StaticCSRFTokenStore{token: token}
157	}
158	
159	// Token returns the stored CSRF token (used by the server to expose it via a
160	// dedicated endpoint or embed it in served HTML).
161	func (s *StaticCSRFTokenStore) Token() string { return s.token }
162	
163	// Validate compares presented to the stored token using a length-equal
164	// constant-time check.
165	func (s *StaticCSRFTokenStore) Validate(presented string) bool {
166		if presented == "" || len(presented) != len(s.token) {
167			return false
168		}
169		var diff byte
170		for i := 0; i < len(s.token); i++ {
171			diff |= s.token[i] ^ presented[i]
172		}
173		return diff == 0
174	}
