189	// OperatorPromptSubmit implements the operatorPromptSubmit mutation: it
190	// validates the CSRF token from the request header, deduplicates within a
191	// 24h window by idempotency key, and (on first submission) creates a new
192	// operator-prompt bead in the proposed status with an audit event capturing
193	// the originating identity (localhost user OR ts-net WhoIs).
194	func (r *mutationResolver) OperatorPromptSubmit(ctx context.Context, input OperatorPromptSubmitInput) (*OperatorPromptSubmitResult, error) {
195		if r.WorkingDir == "" {
196			return nil, fmt.Errorf("working directory not configured")
197		}
198		if strings.TrimSpace(input.Prompt) == "" {
199			return nil, fmt.Errorf("operator-prompts: prompt is required")
200		}
201		if strings.TrimSpace(input.IdempotencyKey) == "" {
202			return nil, fmt.Errorf("operator-prompts: idempotency key is required")
203		}
204	
205		httpReq := httpRequestFromContext(ctx)
206		if httpReq == nil {
207			// No request context means we cannot enforce CSRF, which is the
208			// whole point of the gate. Refuse rather than fail open.
209			return nil, errCSRF
210		}
211		presented := httpReq.Header.Get(CSRFHeaderName)
212		if r.CSRFTokens == nil || !r.CSRFTokens.Validate(presented) {
213			return nil, errCSRF
214		}
215	
216		cache := r.OperatorPromptIdempotency
217		if cache == nil {
218			return nil, fmt.Errorf("operator-prompts: idempotency cache not configured")
219		}
220	
221		store := r.beadStore()
222		if id, ok := cache.Lookup(input.IdempotencyKey); ok {
223			existing, err := store.Get(id)
224			if err == nil {
225				return &OperatorPromptSubmitResult{
226					Bead:         beadModelFromBead(existing),
227					Deduplicated: true,
228				}, nil
229			}
230			// Cached ID points to a missing bead — fall through and create a
231			// fresh bead, overwriting the stale entry below.
232		}
233	
234		tier := bead.DefaultPriority
235		if input.Tier != nil {
236			tier = *input.Tier
237		}
238		b := bead.NewOperatorPromptBead(input.Prompt, tier)
239		if err := store.Create(b); err != nil {
240			return nil, err
241		}
242	
243		identity := operatorPromptIdentity(httpReq)
244		auditBody := fmt.Sprintf(
245			"identity=%s remote_addr=%s tailscale_user=%s tailscale_node=%s idempotency_key=%s",
246			identity.kind,
247			httpReq.RemoteAddr,
248			httpReq.Header.Get("X-Tailscale-User"),
249			httpReq.Header.Get("X-Tailscale-Node"),
250			input.IdempotencyKey,
251		)
252		if err := store.AppendEvent(b.ID, bead.BeadEvent{
253			Kind:    OperatorPromptEventKind,
254			Summary: "operator prompt submitted",
255			Body:    auditBody,
256			Actor:   identity.actor,
257			Source:  "graphql:operatorPromptSubmit",
258		}); err != nil {
259			return nil, fmt.Errorf("operator-prompts: append audit event: %w", err)
260		}
261	
262		cache.Store(input.IdempotencyKey, b.ID)
263	
264		// Auto-approve path: only when the caller asked for it AND the identity
265		// is on the per-project allowlist. ts-net identities never qualify
266		// (locked Story 15 decision). On denial we leave the bead in proposed
267		// and return autoApproved=false; the caller can still issue a manual
268		// operatorPromptApprove later from a permitted identity.
269		autoApproved := false
270		if input.AutoApprove != nil && *input.AutoApprove {
271			if r.canAutoApprove(identity) {
272				if err := store.Update(b.ID, func(updated *bead.Bead) {
273					updated.Status = bead.StatusOpen
274				}); err != nil {
275					return nil, fmt.Errorf("operator-prompts: auto-approve update: %w", err)
276				}
277				if err := store.AppendEvent(b.ID, bead.BeadEvent{
278					Kind:    OperatorPromptApproveEventKind,
279					Summary: "operator prompt auto-approved on submit",
280					Body:    fmt.Sprintf("identity=%s actor=%s", identity.kind, identity.actor),
281					Actor:   identity.actor,
282					Source:  "graphql:operatorPromptSubmit",
283				}); err != nil {
284					return nil, fmt.Errorf("operator-prompts: append auto-approve event: %w", err)
285				}
286				autoApproved = true
287			}
288		}
289	
290		// Re-read so the audit event materializes in the returned snapshot.
291		persisted, err := store.Get(b.ID)
292		if err != nil {
293			return nil, err
294		}
295		return &OperatorPromptSubmitResult{
296			Bead:         beadModelFromBead(persisted),
297			Deduplicated: false,
298			AutoApproved: autoApproved,
299		}, nil
300	}
