302	// OperatorPromptApprove implements the operatorPromptApprove mutation:
303	// validates CSRF, verifies the bead is a proposed operator-prompt, enforces
304	// the per-project allowlist (ts-net identities are never eligible per
305	// locked decision), transitions proposed → open, and appends an audit event
306	// recording the approver.
307	func (r *mutationResolver) OperatorPromptApprove(ctx context.Context, id string) (*OperatorPromptApproveResult, error) {
308		httpReq, ident, err := r.requireOperatorPromptCSRF(ctx)
309		if err != nil {
310			return nil, err
311		}
312		if !r.canAutoApprove(ident) {
313			return nil, errAutoApproveDenied
314		}
315	
316		store := r.beadStore()
317		existing, err := store.Get(id)
318		if err != nil {
319			return nil, err
320		}
321		if existing.IssueType != bead.IssueTypeOperatorPrompt {
322			return nil, fmt.Errorf("operator-prompts: bead %s is not an operator-prompt (issue_type=%q)", id, existing.IssueType)
323		}
324		if existing.Status != bead.StatusProposed {
325			return nil, fmt.Errorf("operator-prompts: bead %s is not in proposed status (got %q); cannot approve", id, existing.Status)
326		}
327		if err := store.Update(id, func(b *bead.Bead) {
328			b.Status = bead.StatusOpen
329		}); err != nil {
330			return nil, err
331		}
332		if err := store.AppendEvent(id, bead.BeadEvent{
333			Kind:    OperatorPromptApproveEventKind,
334			Summary: "operator prompt approved",
335			Body:    fmt.Sprintf("identity=%s actor=%s remote_addr=%s", ident.kind, ident.actor, httpReq.RemoteAddr),
336			Actor:   ident.actor,
337			Source:  "graphql:operatorPromptApprove",
338		}); err != nil {
339			return nil, fmt.Errorf("operator-prompts: append approve audit event: %w", err)
340		}
341		persisted, err := store.Get(id)
342		if err != nil {
343			return nil, err
344		}
345		return &OperatorPromptApproveResult{Bead: beadModelFromBead(persisted)}, nil
346	}
