393	// requireOperatorPromptCSRF is the shared preamble for the approve and
394	// cancel mutations. It pulls the originating *http.Request from context
395	// (the server's GraphQL handler installs it via WithHTTPRequest), enforces
396	// the CSRF token check against the configured store, and returns the
397	// classified identity.
398	func (r *mutationResolver) requireOperatorPromptCSRF(ctx context.Context) (*http.Request, operatorPromptIdentityInfo, error) {
399		if r.WorkingDir == "" {
400			return nil, operatorPromptIdentityInfo{}, fmt.Errorf("working directory not configured")
401		}
402		httpReq := httpRequestFromContext(ctx)
403		if httpReq == nil {
404			return nil, operatorPromptIdentityInfo{}, errCSRF
405		}
406		presented := httpReq.Header.Get(CSRFHeaderName)
407		if r.CSRFTokens == nil || !r.CSRFTokens.Validate(presented) {
408			return nil, operatorPromptIdentityInfo{}, errCSRF
409		}
410		return httpReq, operatorPromptIdentity(httpReq), nil
411	}
412	
413	// canAutoApprove reports whether ident is authorized to approve operator
414	// prompts under the resolver's allowlist. ts-net identities are denied
415	// unconditionally (locked Story 15 decision). For localhost identities,
416	// the literal sentinel "localhost" matches any actor; otherwise the
417	// allowlist entry must equal the identity's actor string.
418	func (r *Resolver) canAutoApprove(ident operatorPromptIdentityInfo) bool {
419		if ident.kind != "localhost" {
420			return false
421		}
422		if len(r.OperatorPromptAutoApproveAllowlist) == 0 {
423			return false
424		}
425		for _, entry := range r.OperatorPromptAutoApproveAllowlist {
426			if entry == OperatorPromptAllowlistLocalhostSentinel {
427				return true
428			}
429			if entry == ident.actor {
430				return true
431			}
432		}
433		return false
434	}
435	
436	type operatorPromptIdentityInfo struct {
437		kind  string // "tsnet" or "localhost"
438		actor string
439	}
440	
441	// operatorPromptIdentity classifies the originating identity for audit
442	// logging. ts-net peers are identified by the X-Tailscale-User header
443	// injected by tsnetMiddleware; loopback callers fall back to a
444	// "localhost:<remote-addr>" actor string. A bare "anonymous" actor is used
445	// only when neither signal is present (which should not occur because
446	// requireTrusted gates the GraphQL endpoint).
447	func operatorPromptIdentity(r *http.Request) operatorPromptIdentityInfo {
448		if user := r.Header.Get("X-Tailscale-User"); user != "" {
449			return operatorPromptIdentityInfo{kind: "tsnet", actor: user}
450		}
451		if r.RemoteAddr != "" {
452			return operatorPromptIdentityInfo{kind: "localhost", actor: "localhost:" + r.RemoteAddr}
453		}
454		return operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
455	}
